3_real_world_example.code:
console.log('Stack: pushing main script');

// All 3 get sent to Web APIs. They finish almost instantly 
// and enter the Task Queue in order: A, B, C.
setTimeout(() => console.log('Queue: Callback A'), 0);
setTimeout(() => console.log('Queue: Callback B'), 0);
setTimeout(() => console.log('Queue: Callback C'), 0);

// This occupies the Call Stack. The Queue must wait.
function heavyWork() {
  console.log('Stack: Doing heavy work');
  for(let i=0; i<1e9; i++) {}
}
heavyWork();

console.log('Stack: main script done, popping off');

// Output:
// Stack: pushing main script
// Stack: Doing heavy work
// Stack: main script done, popping off
// [Stack is now empty! Event Loop moves callbacks]
// Queue: Callback A
// Queue: Callback B
// Queue: Callback C

